// Package skiplist implements a concurrent skip list with lazy synchronization.
// The skip list uses atomics for reads and fine-grained locking for writes,
// implementing the lazy synchronization algorithm from Heller et al.
package skiplist

import (
	"cmp"
	"context"
	"math/rand"
	"sync"
	"sync/atomic"
)

const maxLevel = 20
const probability = 0.25

// UpdateCheck is a function called by Upsert under a node lock to determine
// the new value. It receives the key, current value, and whether the key exists.
// If it returns an error, the upsert is not performed.
type UpdateCheck[K cmp.Ordered, V any] func(key K, currValue V, exists bool) (newValue V, err error)

// Pair holds a key-value pair returned by Query.
type Pair[K cmp.Ordered, V any] struct {
	Key   K
	Value V
}

// DBIndex is the interface that the skip list implements.
type DBIndex[K cmp.Ordered, V any] interface {
	Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error)
	Remove(key K) (removedValue V, removed bool)
	Find(key K) (foundValue V, found bool)
	Query(ctx context.Context, start K, end K) (results []Pair[K, V], err error)
}

// node is a node in the skip list.
type node[K cmp.Ordered, V any] struct {
	key         K
	value       atomic.Pointer[V]
	topLevel    int
	next        [maxLevel]atomic.Pointer[node[K, V]]
	mu          sync.Mutex
	marked      atomic.Bool
	fullyLinked atomic.Bool
	isHead      bool
	isTail      bool
}

// SkipList is a concurrent skip list.
type SkipList[K cmp.Ordered, V any] struct {
	head  *node[K, V]
	tail  *node[K, V]
	level int
	mu    sync.Mutex
}

// New creates a new empty skip list.
func New[K cmp.Ordered, V any]() *SkipList[K, V] {
	head := &node[K, V]{topLevel: maxLevel - 1, isHead: true}
	tail := &node[K, V]{topLevel: maxLevel - 1, isTail: true}
	for i := 0; i < maxLevel; i++ {
		head.next[i].Store(tail)
	}
	head.fullyLinked.Store(true)
	tail.fullyLinked.Store(true)
	return &SkipList[K, V]{
		head:  head,
		tail:  tail,
		level: 1,
	}
}

// nodeCompare compares n's key to key.
// Returns negative if n < key, 0 if equal, positive if n > key.
// Sentinel nodes (head/tail) always compare as -inf/+inf.
func (sl *SkipList[K, V]) nodeCompare(n *node[K, V], key K) int {
	if n.isHead {
		return -1
	}
	if n.isTail {
		return 1
	}
	return cmp.Compare(n.key, key)
}

// randomLevel returns a random level for a new node.
func randomLevel() int {
	level := 1
	for level < maxLevel && rand.Float64() < probability {
		level++
	}
	return level
}

// find performs a search for the given key. It returns:
// - found: true if a fully linked, non-marked node with the key exists
// - preds: predecessor nodes at each level
// - succs: successor nodes at each level (succs[0] is either the found node or the first node > key)
func (sl *SkipList[K, V]) find(key K) (found bool, preds [maxLevel]*node[K, V], succs [maxLevel]*node[K, V]) {
	var lFound int = -1
retry:
	pred := sl.head
	for level := maxLevel - 1; level >= 0; level-- {
		curr := pred.next[level].Load()
		for sl.nodeCompare(curr, key) < 0 {
			pred = curr
			curr = pred.next[level].Load()
		}
		if lFound == -1 && sl.nodeCompare(curr, key) == 0 {
			lFound = level
		}
		preds[level] = pred
		succs[level] = curr
	}

	if lFound != -1 {
		candidate := succs[lFound]
		found = candidate.fullyLinked.Load() && !candidate.marked.Load()
		if !found {
			// Node is being added or removed; retry
			goto retry
		}
	}
	return found, preds, succs
}

// Upsert inserts or updates a key in the skip list.
// The check function is called under a lock; if it returns an error, the operation is aborted.
// Returns (true, nil) if the key was updated, (false, nil) if it was inserted,
// or (false, error) if the check function returned an error.
func (sl *SkipList[K, V]) Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error) {
	topLevel := randomLevel() - 1

	for {
		found, preds, succs := sl.find(key)

		if found {
			// Key exists; update it under the node's lock
			nodeToUpdate := succs[0]
			nodeToUpdate.mu.Lock()
			if nodeToUpdate.marked.Load() {
				// Node was removed between find and lock; retry
				nodeToUpdate.mu.Unlock()
				continue
			}

			var currValue V
			if ptr := nodeToUpdate.value.Load(); ptr != nil {
				currValue = *ptr
			}

			newValue, err := check(key, currValue, true)
			if err != nil {
				nodeToUpdate.mu.Unlock()
				return true, err
			}
			nodeToUpdate.value.Store(&newValue)
			nodeToUpdate.mu.Unlock()
			return true, nil
		}

		// Key does not exist; insert it
		// Lock predecessors from bottom up
		highestLocked := -1
		var lockedPreds [maxLevel]*node[K, V]
		valid := true

		for level := 0; valid && level <= topLevel; level++ {
			pred := preds[level]
			succ := succs[level]
			pred.mu.Lock()
			highestLocked = level
			lockedPreds[level] = pred

			// Validate: pred not marked, pred still points to succ
			valid = !pred.marked.Load() && pred.next[level].Load() == succ
		}

		if !valid {
			// Unlock and retry
			for level := highestLocked; level >= 0; level-- {
				lockedPreds[level].mu.Unlock()
			}
			continue
		}

		// Call check function with no existing value
		var zero V
		newValue, err := check(key, zero, false)
		if err != nil {
			// Don't insert
			for level := highestLocked; level >= 0; level-- {
				lockedPreds[level].mu.Unlock()
			}
			return false, err
		}

		// Create new node
		newNode := &node[K, V]{
			key:      key,
			topLevel: topLevel,
		}
		newNode.value.Store(&newValue)

		// Link at each level
		for level := 0; level <= topLevel; level++ {
			newNode.next[level].Store(succs[level])
			preds[level].next[level].Store(newNode)
		}

		newNode.fullyLinked.Store(true)

		// Unlock
		for level := highestLocked; level >= 0; level-- {
			lockedPreds[level].mu.Unlock()
		}

		return false, nil
	}
}

// Remove removes the node with the given key from the skip list.
// Returns the removed value and true if the key was found and removed.
func (sl *SkipList[K, V]) Remove(key K) (removedValue V, removed bool) {
	var nodeToDelete *node[K, V]
	isMarked := false
	topLevel := -1

	for {
		found, preds, succs := sl.find(key)

		if isMarked || (found && canDelete(succs[0], topLevel)) {
			if !isMarked {
				// Logically delete (mark) the node
				nodeToDelete = succs[0]
				topLevel = nodeToDelete.topLevel
				nodeToDelete.mu.Lock()
				if nodeToDelete.marked.Load() {
					// Already deleted by another goroutine
					nodeToDelete.mu.Unlock()
					var zero V
					return zero, false
				}
				nodeToDelete.marked.Store(true)
				isMarked = true

				if ptr := nodeToDelete.value.Load(); ptr != nil {
					removedValue = *ptr
				}
				nodeToDelete.mu.Unlock()
			}

			// Physically remove the node
			highestLocked := -1
			var lockedPreds [maxLevel]*node[K, V]
			valid := true

			for level := 0; valid && level <= topLevel; level++ {
				pred := preds[level]
				pred.mu.Lock()
				highestLocked = level
				lockedPreds[level] = pred
				valid = !pred.marked.Load() && pred.next[level].Load() == nodeToDelete
			}

			if !valid {
				// Unlock and retry
				for level := highestLocked; level >= 0; level-- {
					lockedPreds[level].mu.Unlock()
				}
				continue
			}

			// Physically unlink
			for level := topLevel; level >= 0; level-- {
				preds[level].next[level].Store(nodeToDelete.next[level].Load())
			}

			// Unlock
			for level := highestLocked; level >= 0; level-- {
				lockedPreds[level].mu.Unlock()
			}

			return removedValue, true
		} else {
			var zero V
			return zero, false
		}
	}
}

// canDelete returns true if the node can be deleted (fully linked and at the expected level).
func canDelete[K cmp.Ordered, V any](node *node[K, V], topLevel int) bool {
	return node.fullyLinked.Load() && node.topLevel == topLevel
}

// Find looks up a key in the skip list without modifying it.
// Returns the value and true if found, or the zero value and false if not found.
func (sl *SkipList[K, V]) Find(key K) (foundValue V, found bool) {
	pred := sl.head
	for level := maxLevel - 1; level >= 0; level-- {
		curr := pred.next[level].Load()
		for sl.nodeCompare(curr, key) < 0 {
			pred = curr
			curr = pred.next[level].Load()
		}
		if sl.nodeCompare(curr, key) == 0 {
			if curr.fullyLinked.Load() && !curr.marked.Load() {
				if ptr := curr.value.Load(); ptr != nil {
					return *ptr, true
				}
			}
			break
		}
	}
	var zero V
	return zero, false
}

// Query returns all elements in the skip list with keys in [start, end].
// If start is the zero value of K, there is no lower bound.
// If end is the zero value of K, there is no upper bound.
// The results are returned in ascending order of key.
func (sl *SkipList[K, V]) Query(ctx context.Context, start K, end K) ([]Pair[K, V], error) {
	var zero K
	hasStart := cmp.Compare(start, zero) != 0
	hasEnd := cmp.Compare(end, zero) != 0

	var results []Pair[K, V]

	// Iterate at level 0
	curr := sl.head.next[0].Load()
	for curr != sl.tail {
		if err := ctx.Err(); err != nil {
			return nil, err
		}

		if !curr.marked.Load() && curr.fullyLinked.Load() {
			if hasStart && cmp.Compare(curr.key, start) < 0 {
				curr = curr.next[0].Load()
				continue
			}
			if hasEnd && cmp.Compare(curr.key, end) > 0 {
				break
			}
			if ptr := curr.value.Load(); ptr != nil {
				results = append(results, Pair[K, V]{Key: curr.key, Value: *ptr})
			}
		}

		curr = curr.next[0].Load()
	}

	return results, nil
}

// Len returns the approximate number of elements in the skip list.
// This is an O(n) operation.
func (sl *SkipList[K, V]) Len() int {
	count := 0
	curr := sl.head.next[0].Load()
	for curr != sl.tail {
		if !curr.marked.Load() {
			count++
		}
		curr = curr.next[0].Load()
	}
	return count
}

// ForEach calls f for each element in the skip list in key order.
// If f returns false, iteration stops.
func (sl *SkipList[K, V]) ForEach(f func(key K, value V) bool) {
	curr := sl.head.next[0].Load()
	for curr != sl.tail {
		if !curr.marked.Load() && curr.fullyLinked.Load() {
			if ptr := curr.value.Load(); ptr != nil {
				if !f(curr.key, *ptr) {
					return
				}
			}
		}
		curr = curr.next[0].Load()
	}
}

// Ensure SkipList implements DBIndex.
var _ DBIndex[string, any] = (*SkipList[string, any])(nil)

// Package db implements the in-memory document database for OwlDB.
// It uses a concurrent skip list as the underlying data structure for collections.
package db

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"strings"
	"sync"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-p1/jsondata"
	"github.com/RICE-COMP318-FALL24/owldb-p1/skiplist"
)

// Metadata holds the server-generated metadata for each document.
type Metadata struct {
	CreatedBy      string `json:"createdBy"`
	CreatedAt      int64  `json:"createdAt"`
	LastModifiedBy string `json:"lastModifiedBy"`
	LastModifiedAt int64  `json:"lastModifiedAt"`
}

// DocResponse is the response structure for a document retrieval.
type DocResponse struct {
	Path string          `json:"path"`
	Doc  jsondata.JSONValue `json:"doc"`
	Meta Metadata        `json:"meta"`
}

// PatchResult is the response structure for a patch operation.
type PatchResult struct {
	URI         string `json:"uri"`
	PatchFailed bool   `json:"patchFailed"`
	Message     string `json:"message"`
}

// EventType is the type of SSE event.
type EventType string

const (
	EventUpdate EventType = "update"
	EventDelete EventType = "delete"
)

// Event is an SSE event to be sent to subscribers.
type Event struct {
	Type EventType
	Path string
	Doc  *jsondata.JSONValue
	Meta *Metadata
}

// Document represents a single document stored in the database.
type Document struct {
	Body        jsondata.JSONValue
	Meta        Metadata
	Collections *skiplist.SkipList[string, *Collection]
	mu          sync.RWMutex
	// docSubscribers are channels that should be notified when this doc changes
	docSubscribers []chan Event
	dsMu           sync.Mutex
}

// Collection represents a collection of documents stored in a skip list.
type Collection struct {
	Index *skiplist.SkipList[string, *Document]
	// colSubscribers are channels notified when any doc in this collection changes
	colSubscribers []chan Event
	csMu           sync.Mutex
}

// Database represents a single top-level database.
type Database struct {
	TopLevel *Collection // top-level documents
}

// Store is the top-level in-memory store containing all databases.
type Store struct {
	databases *skiplist.SkipList[string, *Database]
}

// NewStore creates a new empty store.
func NewStore() *Store {
	return &Store{
		databases: skiplist.New[string, *Database](),
	}
}

// NewCollection creates a new empty collection.
func NewCollection() *Collection {
	return &Collection{
		Index: skiplist.New[string, *Document](),
	}
}

// NewDatabase creates a new empty database.
func NewDatabase() *Database {
	return &Database{
		TopLevel: NewCollection(),
	}
}

// --- Database management ---

// CreateDatabase creates a new database with the given name.
// Returns an error if it already exists.
func (s *Store) CreateDatabase(name string) error {
	_, err := s.databases.Upsert(name, func(key string, currValue *Database, exists bool) (*Database, error) {
		if exists {
			return nil, fmt.Errorf("database already exists")
		}
		return NewDatabase(), nil
	})
	return err
}

// DeleteDatabase removes the database with the given name.
// Returns the database and true if found, or nil and false if not found.
func (s *Store) DeleteDatabase(name string) (*Database, bool) {
	db, removed := s.databases.Remove(name)
	return db, removed
}

// FindDatabase returns the database with the given name.
func (s *Store) FindDatabase(name string) (*Database, bool) {
	return s.databases.Find(name)
}

// --- Collection operations ---

// getCollection traverses the path and returns the collection at the end.
// pathParts is the sequence of path elements (alternating doc/collection names).
// The last element of pathParts is the collection name.
// Returns the collection and the full path to it, or an error.
func (s *Store) getCollection(dbName string, pathParts []string) (*Collection, error) {
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, fmt.Errorf("database does not exist")
	}

	if len(pathParts) == 0 {
		// Return the top-level collection
		return db.TopLevel, nil
	}

	// pathParts alternates: doc, collection, doc, collection...
	// For a collection path, the pattern is: doc0, col0, doc1, col1, ...
	// pathParts for a collection should have even length (ending with collection name)
	// Actually: pathParts for top-level collection = []
	// pathParts for /db/doc/col/ = ["doc", "col"]
	// pathParts for /db/doc/col/doc2/col2/ = ["doc", "col", "doc2", "col2"]

	if len(pathParts)%2 != 0 {
		return nil, fmt.Errorf("invalid collection path")
	}

	col := db.TopLevel
	for i := 0; i < len(pathParts); i += 2 {
		docName := pathParts[i]
		colName := pathParts[i+1]

		doc, found := col.Index.Find(docName)
		if !found {
			return nil, fmt.Errorf("document does not exist")
		}

		subCol, found := doc.Collections.Find(colName)
		if !found {
			return nil, fmt.Errorf("collection does not exist")
		}
		col = subCol
	}

	return col, nil
}

// CreateCollection creates a new collection at the specified path.
// pathParts ends with the collection name; the parent document must exist.
func (s *Store) CreateCollection(dbName string, pathParts []string) error {
	if len(pathParts) == 0 {
		return fmt.Errorf("invalid collection path")
	}
	if len(pathParts)%2 != 1 {
		// For creating a collection:
		// /db/col/ → pathParts = ["col"] (length 1 = odd)
		// /db/doc/col/doc2/col2/ → pathParts = ["doc", "col", "doc2", "col2", "colNew"] (length 5 = odd?)
		// Actually: looking at the URL patterns:
		// PUT /v1/{database}/{collectionPath}/ creates a collection
		// The collection path is doc/col/doc/col/.../newcol
		// So the parent is the last document in the path
		return fmt.Errorf("invalid collection path")
	}

	db, found := s.databases.Find(dbName)
	if !found {
		return fmt.Errorf("database does not exist")
	}

	if len(pathParts) == 1 {
		// Creating top-level collection inside a database - not supported!
		// Actually, looking at the API: PUT /v1/{database}/{collectionPath}/
		// A database is NOT a document, so a collection at path /db/myCol/ means
		// myCol is a subcollection. But the database itself has a top-level collection.
		// Actually re-reading: "PUT /v1/{database}/{collectionPath}/ - Create new collection"
		// "The entire collection path must already exist in the database except the final component naming the collection."
		// So for /v1/db/col/, the parent must be the database (which has the top-level collection).
		// But wait - can you create a collection directly in a database?
		// Looking at the path alternating rule: /db/doc/col/
		// This means: /db/ is the database, doc is a document, col is a collection.
		// So a collection must always be inside a document, not directly in a database.
		// Shortest collection path: /db/doc/col/ → pathParts = ["doc", "col"] (even!)
		// Hmm, let me re-read...
		//
		// Re-reading: "PUT /v1/{database}/{collectionPath}/"
		// "The entire collection path must already exist in the database except the final component naming the collection."
		//
		// The collection path in the URL is {collectionPath}. This is the path after the database name.
		// E.g., /v1/db/doc/col/ → database=db, collectionPath=doc/col
		// The "doc" must exist in db, and "col" is the new collection inside doc.
		//
		// So collection creation path parts (after stripping trailing slash and database) would be:
		// doc/col → ["doc", "col"] (length 2 = even)
		// doc1/col1/doc2/col2 → ["doc1", "col1", "doc2", "col2"] (length 4 = even? but last is collection)
		//
		// Wait, this doesn't work with my odd-length check. Let me reconsider.
		//
		// For creating /v1/db/doc/col/:
		// pathParts after db = ["doc", "col"] (doc exists, col is new)
		// Length = 2 = even
		// So length should be even!
		//
		// For creating /v1/db/:
		// That's creating a database, not a collection.
		// For a collection path, it must alternate doc/col.
		// So pathParts for collection creation must have length >= 2 and be even.
		return fmt.Errorf("invalid collection path")
	}

	// Navigate to parent document
	col := db.TopLevel
	for i := 0; i < len(pathParts)-2; i += 2 {
		docName := pathParts[i]
		colName := pathParts[i+1]

		doc, found := col.Index.Find(docName)
		if !found {
			return fmt.Errorf("document does not exist")
		}

		subCol, found := doc.Collections.Find(colName)
		if !found {
			return fmt.Errorf("collection does not exist")
		}
		col = subCol
	}

	// Now we need to find the parent document and create the new collection in it
	parentDocName := pathParts[len(pathParts)-2]
	newColName := pathParts[len(pathParts)-1]

	parentDoc, found := col.Index.Find(parentDocName)
	if !found {
		return fmt.Errorf("document does not exist")
	}

	_, err := parentDoc.Collections.Upsert(newColName, func(key string, curr *Collection, exists bool) (*Collection, error) {
		if exists {
			return nil, fmt.Errorf("collection already exists")
		}
		return NewCollection(), nil
	})
	return err
}

// DeleteCollection removes a collection and all its contents.
// Returns the collection and true if found.
func (s *Store) DeleteCollection(dbName string, pathParts []string) (*Collection, bool) {
	if len(pathParts) == 0 {
		return nil, false
	}

	db, found := s.databases.Find(dbName)
	if !found {
		return nil, false
	}

	if len(pathParts) < 2 {
		// Can't delete the top-level collection directly
		return nil, false
	}

	// Navigate to the parent document
	col := db.TopLevel
	for i := 0; i < len(pathParts)-2; i += 2 {
		docName := pathParts[i]
		colName := pathParts[i+1]

		doc, found := col.Index.Find(docName)
		if !found {
			return nil, false
		}
		subCol, found := doc.Collections.Find(colName)
		if !found {
			return nil, false
		}
		col = subCol
	}

	parentDocName := pathParts[len(pathParts)-2]
	colToDelete := pathParts[len(pathParts)-1]

	parentDoc, found := col.Index.Find(parentDocName)
	if !found {
		return nil, false
	}

	removedCol, removed := parentDoc.Collections.Remove(colToDelete)
	return removedCol, removed
}

// --- Document operations ---

// GetDocument retrieves a document at the given path.
func (s *Store) GetDocument(dbName string, pathParts []string) (*Document, error) {
	if len(pathParts) == 0 {
		return nil, fmt.Errorf("document does not exist")
	}

	// pathParts for document: for /db/doc → ["doc"]
	// For /db/doc/col/doc2 → ["doc", "col", "doc2"]
	// Length must be odd

	db, found := s.databases.Find(dbName)
	if !found {
		return nil, fmt.Errorf("database does not exist")
	}

	col := db.TopLevel
	for i := 0; i < len(pathParts)-1; i += 2 {
		docName := pathParts[i]
		colName := pathParts[i+1]

		doc, found := col.Index.Find(docName)
		if !found {
			return nil, fmt.Errorf("document does not exist")
		}
		subCol, found := doc.Collections.Find(colName)
		if !found {
			return nil, fmt.Errorf("collection does not exist")
		}
		col = subCol
	}

	docName := pathParts[len(pathParts)-1]
	doc, found := col.Index.Find(docName)
	if !found {
		return nil, fmt.Errorf("document does not exist")
	}
	return doc, nil
}

// PutDocument creates or updates a document at the given path.
// mode can be "overwrite" (default) or "nooverwrite".
// Returns (true, nil) if the document was updated, (false, nil) if created,
// or an error if the operation failed.
func (s *Store) PutDocument(dbName string, pathParts []string, body jsondata.JSONValue, username string, mode string) (bool, error) {
	if len(pathParts) == 0 {
		return false, fmt.Errorf("invalid document path")
	}

	db, found := s.databases.Find(dbName)
	if !found {
		return false, fmt.Errorf("database does not exist")
	}

	// Navigate to the parent collection
	col, err := s.navigateToParentCollection(db, pathParts)
	if err != nil {
		return false, err
	}

	docName := pathParts[len(pathParts)-1]
	now := time.Now().UnixMilli()

	var wasUpdated bool
	var updateErr error

	updated, err := col.Index.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		if exists {
			if mode == "nooverwrite" {
				updateErr = fmt.Errorf("document already exists")
				return nil, updateErr
			}
			// Update existing document
			curr.mu.Lock()
			curr.Body = body
			curr.Meta.LastModifiedBy = username
			curr.Meta.LastModifiedAt = now
			curr.mu.Unlock()
			wasUpdated = true
			return curr, nil
		}
		// Create new document
		doc := &Document{
			Body:        body,
			Meta:        Metadata{
				CreatedBy:      username,
				CreatedAt:      now,
				LastModifiedBy: username,
				LastModifiedAt: now,
			},
			Collections: skiplist.New[string, *Collection](),
		}
		wasUpdated = false
		return doc, nil
	})
	if err != nil {
		if updateErr != nil {
			// nooverwrite conflict
			return false, &ConflictError{Message: "document already exists"}
		}
		return false, err
	}
	_ = updated

	// Notify subscribers
	doc, found := col.Index.Find(docName)
	if found {
		// Build full path for notification
		fullPath := buildDocPath(dbName, pathParts)
		doc.mu.RLock()
		body := doc.Body
		meta := doc.Meta
		doc.mu.RUnlock()

		event := Event{
			Type: EventUpdate,
			Path: fullPath,
			Doc:  &body,
			Meta: &meta,
		}
		notifyDocSubscribers(doc, event)
		notifyColSubscribers(col, event)
	}

	return wasUpdated, nil
}

// PostDocument creates a new document with a server-generated name.
// Returns the generated document name or an error.
func (s *Store) PostDocument(dbName string, pathParts []string, body jsondata.JSONValue, username string) (string, error) {
	db, found := s.databases.Find(dbName)
	if !found {
		return "", fmt.Errorf("database does not exist")
	}

	var col *Collection
	var err error

	if len(pathParts) == 0 {
		col = db.TopLevel
	} else {
		col, err = s.getCollection(dbName, pathParts)
		if err != nil {
			return "", err
		}
	}

	// Generate a unique document name
	docName := generateID()
	now := time.Now().UnixMilli()

	doc := &Document{
		Body: body,
		Meta: Metadata{
			CreatedBy:      username,
			CreatedAt:      now,
			LastModifiedBy: username,
			LastModifiedAt: now,
		},
		Collections: skiplist.New[string, *Collection](),
	}

	_, insertErr := col.Index.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		if exists {
			return nil, fmt.Errorf("document already exists")
		}
		return doc, nil
	})
	if insertErr != nil {
		return "", insertErr
	}

	// Notify subscribers
	allParts := append(pathParts, docName)
	fullPath := buildDocPath(dbName, allParts)
	event := Event{
		Type: EventUpdate,
		Path: fullPath,
		Doc:  &body,
		Meta: &doc.Meta,
	}
	notifyColSubscribers(col, event)

	return docName, nil
}

// DeleteDocument removes a document at the given path.
// Returns the document and true if found.
func (s *Store) DeleteDocument(dbName string, pathParts []string) (*Document, error) {
	if len(pathParts) == 0 {
		return nil, fmt.Errorf("document does not exist")
	}

	db, found := s.databases.Find(dbName)
	if !found {
		return nil, fmt.Errorf("database does not exist")
	}

	col, err := s.navigateToParentCollection(db, pathParts)
	if err != nil {
		return nil, fmt.Errorf("document does not exist")
	}

	docName := pathParts[len(pathParts)-1]
	removedDoc, removed := col.Index.Remove(docName)
	if !removed {
		return nil, fmt.Errorf("document does not exist")
	}

	// Notify subscribers
	fullPath := buildDocPath(dbName, pathParts)
	event := Event{
		Type: EventDelete,
		Path: fullPath,
	}
	notifyDocSubscribers(removedDoc, event)
	notifyColSubscribers(col, event)

	return removedDoc, nil
}

// QueryCollection returns all documents in a collection within the given key range.
// start and end are the range bounds (inclusive). Empty string means no bound.
func (s *Store) QueryCollection(dbName string, pathParts []string, start, end string) ([]DocResponse, error) {
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, fmt.Errorf("database does not exist")
	}

	var col *Collection
	if len(pathParts) == 0 {
		col = db.TopLevel
	} else {
		var err error
		col, err = s.getCollection(dbName, pathParts)
		if err != nil {
			return nil, err
		}
	}

	ctx := context.Background()
	pairs, err := col.Index.Query(ctx, start, end)
	if err != nil {
		return nil, err
	}

	var results []DocResponse
	for _, pair := range pairs {
		doc := pair.Value
		doc.mu.RLock()
		docParts := buildDocPathParts(dbName, pathParts, pair.Key)
		resp := DocResponse{
			Path: docParts,
			Doc:  doc.Body,
			Meta: doc.Meta,
		}
		doc.mu.RUnlock()
		results = append(results, resp)
	}

	if results == nil {
		results = []DocResponse{}
	}
	return results, nil
}

// navigateToParentCollection finds the collection that directly contains the document.
// pathParts is the path to the document (last element is the document name).
func (s *Store) navigateToParentCollection(db *Database, pathParts []string) (*Collection, error) {
	if len(pathParts) == 1 {
		// Document is directly in the top-level collection
		return db.TopLevel, nil
	}

	// Navigate: doc, col, doc, col, ..., docName
	// Parent is accessed via pathParts[0..len-2]
	col := db.TopLevel
	for i := 0; i < len(pathParts)-1; i += 2 {
		docName := pathParts[i]
		colName := pathParts[i+1]

		doc, found := col.Index.Find(docName)
		if !found {
			return nil, fmt.Errorf("document does not exist")
		}
		subCol, found := doc.Collections.Find(colName)
		if !found {
			return nil, fmt.Errorf("collection does not exist")
		}
		col = subCol
	}
	return col, nil
}

// --- PATCH operations ---

// PatchOperation represents a single patch operation.
type PatchOperation struct {
	Op    string          `json:"op"`
	Path  string          `json:"path"`
	Value jsondata.JSONValue `json:"value"`
}

// PatchDocument applies a list of patches to a document.
// Returns the patch result.
func (s *Store) PatchDocument(dbName string, pathParts []string, patches []PatchOperation, username string) (*PatchResult, error) {
	if len(pathParts) == 0 {
		return nil, fmt.Errorf("document does not exist")
	}

	db, found := s.databases.Find(dbName)
	if !found {
		return nil, fmt.Errorf("database does not exist")
	}

	col, err := s.navigateToParentCollection(db, pathParts)
	if err != nil {
		return nil, fmt.Errorf("document does not exist")
	}

	docName := pathParts[len(pathParts)-1]
	fullPath := buildDocPath(dbName, pathParts)

	result := &PatchResult{URI: fullPath}

	// Apply patches atomically under the document lock
	var patchErr error
	var patchedDoc *Document

	updated, upsertErr := col.Index.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		if !exists {
			patchErr = fmt.Errorf("document does not exist")
			return nil, patchErr
		}

		curr.mu.Lock()
		defer curr.mu.Unlock()

		// Apply patches to a copy
		newBody, err := applyPatches(curr.Body, patches)
		if err != nil {
			result.PatchFailed = true
			result.Message = err.Error()
			// Return curr unchanged (don't modify)
			return curr, nil
		}

		// Update the document
		now := time.Now().UnixMilli()
		curr.Body = newBody
		curr.Meta.LastModifiedBy = username
		curr.Meta.LastModifiedAt = now
		result.PatchFailed = false
		result.Message = "patch applied"
		patchedDoc = curr
		return curr, nil
	})
	_ = updated

	if upsertErr != nil {
		if patchErr != nil {
			return nil, patchErr
		}
		return nil, upsertErr
	}

	// Notify subscribers if patch was applied
	if !result.PatchFailed && patchedDoc != nil {
		patchedDoc.mu.RLock()
		body := patchedDoc.Body
		meta := patchedDoc.Meta
		patchedDoc.mu.RUnlock()

		event := Event{
			Type: EventUpdate,
			Path: fullPath,
			Doc:  &body,
			Meta: &meta,
		}
		notifyDocSubscribers(patchedDoc, event)
		notifyColSubscribers(col, event)
	}

	return result, nil
}

// --- SSE Subscription ---

// SubscribeDocument adds a subscriber channel to a document.
// The channel will receive events when the document is modified or deleted.
func (s *Store) SubscribeDocument(dbName string, pathParts []string) (<-chan Event, func(), error) {
	doc, err := s.GetDocument(dbName, pathParts)
	if err != nil {
		return nil, nil, err
	}

	ch := make(chan Event, 100)
	doc.dsMu.Lock()
	doc.docSubscribers = append(doc.docSubscribers, ch)
	doc.dsMu.Unlock()

	unsubscribe := func() {
		doc.dsMu.Lock()
		for i, sub := range doc.docSubscribers {
			if sub == ch {
				doc.docSubscribers = append(doc.docSubscribers[:i], doc.docSubscribers[i+1:]...)
				break
			}
		}
		doc.dsMu.Unlock()
		close(ch)
	}

	return ch, unsubscribe, nil
}

// SubscribeCollection adds a subscriber channel to a collection.
func (s *Store) SubscribeCollection(dbName string, pathParts []string) (<-chan Event, func(), error) {
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, nil, fmt.Errorf("database does not exist")
	}

	var col *Collection
	if len(pathParts) == 0 {
		col = db.TopLevel
	} else {
		var err error
		col, err = s.getCollection(dbName, pathParts)
		if err != nil {
			return nil, nil, err
		}
	}

	ch := make(chan Event, 100)
	col.csMu.Lock()
	col.colSubscribers = append(col.colSubscribers, ch)
	col.csMu.Unlock()

	unsubscribe := func() {
		col.csMu.Lock()
		for i, sub := range col.colSubscribers {
			if sub == ch {
				col.colSubscribers = append(col.colSubscribers[:i], col.colSubscribers[i+1:]...)
				break
			}
		}
		col.csMu.Unlock()
		close(ch)
	}

	return ch, unsubscribe, nil
}

// notifyDocSubscribers sends an event to all document subscribers.
func notifyDocSubscribers(doc *Document, event Event) {
	doc.dsMu.Lock()
	subs := make([]chan Event, len(doc.docSubscribers))
	copy(subs, doc.docSubscribers)
	doc.dsMu.Unlock()

	for _, ch := range subs {
		select {
		case ch <- event:
		default:
			// Drop event if channel is full
		}
	}
}

// notifyColSubscribers sends an event to all collection subscribers.
func notifyColSubscribers(col *Collection, event Event) {
	col.csMu.Lock()
	subs := make([]chan Event, len(col.colSubscribers))
	copy(subs, col.colSubscribers)
	col.csMu.Unlock()

	for _, ch := range subs {
		select {
		case ch <- event:
		default:
			// Drop event if channel is full
		}
	}
}

