// ConflictError is returned when a nooverwrite PUT finds an existing document.
type ConflictError struct {
	Message string
}

func (e *ConflictError) Error() string {
	return e.Message
}

// buildDocPath builds the full document path for responses.
func buildDocPath(dbName string, pathParts []string) string {
	return "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
}

// buildDocPathParts builds the full document path for a document in a collection.
func buildDocPathParts(dbName string, colParts []string, docName string) string {
	if len(colParts) == 0 {
		return "/v1/" + dbName + "/" + docName
	}
	return "/v1/" + dbName + "/" + strings.Join(colParts, "/") + "/" + docName
}

// generateID generates a random unique document name.
func generateID() string {
	const chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	b := make([]byte, 14)
	for i := range b {
		b[i] = chars[randIntn(len(chars))]
	}
	return string(b)
}

var randMu sync.Mutex

func randIntn(n int) int {
	randMu.Lock()
	defer randMu.Unlock()
	return int(randUint64() % uint64(n))
}

var globalRandState uint64 = 0x12345678ABCDEF01

func randUint64() uint64 {
	// Simple xorshift64
	randMu.Lock()
	x := globalRandState
	x ^= x << 13
	x ^= x >> 7
	x ^= x << 17
	globalRandState = x
	randMu.Unlock()
	return x
}

// --- JSON Patch Implementation ---

// parsePointer parses a JSON pointer string into segments.
// The pointer must start with "/" or be "".
func parsePointer(ptr string) ([]string, error) {
	if ptr == "" {
		return nil, nil
	}
	if !strings.HasPrefix(ptr, "/") {
		return nil, fmt.Errorf("invalid JSON pointer: must start with /")
	}
	parts := strings.Split(ptr[1:], "/")
	// Unescape JSON pointer sequences
	result := make([]string, len(parts))
	for i, p := range parts {
		p = strings.ReplaceAll(p, "~1", "/")
		p = strings.ReplaceAll(p, "~0", "~")
		result[i] = p
	}
	return result, nil
}

// applyPatches applies a list of patches to a document body.
// Returns the modified body or an error.
func applyPatches(body jsondata.JSONValue, patches []PatchOperation) (jsondata.JSONValue, error) {
	current := body

	for _, patch := range patches {
		segments, err := parsePointer(patch.Path)
		if err != nil {
			return body, fmt.Errorf("invalid path %q: %w", patch.Path, err)
		}

		var applyErr error
		newBody, err := applyPatch(current, segments, patch.Op, patch.Value)
		if err != nil {
			applyErr = err
		}
		if applyErr != nil {
			return body, applyErr
		}
		current = newBody
	}

	return current, nil
}

// applyPatch applies a single patch operation to a JSON value.
func applyPatch(body jsondata.JSONValue, segments []string, op string, value jsondata.JSONValue) (jsondata.JSONValue, error) {
	switch op {
	case "ArrayAdd":
		return applyArrayOp(body, segments, value, true)
	case "ArrayRemove":
		return applyArrayOp(body, segments, value, false)
	case "ObjectAdd":
		return applyObjectAdd(body, segments, value)
	default:
		return body, fmt.Errorf("unknown op: %s", op)
	}
}

// patchMapVisitor is a visitor for applying patch operations to a map.
type patchMapVisitor struct {
	segments []string
	op       string
	value    jsondata.JSONValue
}

func (v *patchMapVisitor) Map(m map[string]jsondata.JSONValue) (jsondata.JSONValue, error) {
	if len(v.segments) == 0 {
		// We're at the target which is a map - this shouldn't happen for our ops
		return jsondata.JSONValue{}, fmt.Errorf("unexpected map at target")
	}

	key := v.segments[0]
	remaining := v.segments[1:]

	if len(remaining) == 0 {
		// Last segment: apply operation
		switch v.op {
		case "ArrayAdd", "ArrayRemove":
			// path refers to an array in this map
			arrVal, exists := m[key]
			if !exists {
				return jsondata.JSONValue{}, fmt.Errorf("path element %q not found", key)
			}
			newArr, err := applyArrayOpDirect(arrVal, v.value, v.op == "ArrayAdd")
			if err != nil {
				return jsondata.JSONValue{}, err
			}
			// Create modified copy of map
			newMap := make(map[string]jsondata.JSONValue, len(m))
			for k, v := range m {
				newMap[k] = v
			}
			newMap[key] = newArr
			return jsondata.NewJSONValue(newMap)
		case "ObjectAdd":
			// path points to an object in this map; key is the property to add
			// Wait - for ObjectAdd, the path up to but not including the last element is the object.
			// If we're at the last segment, then the CURRENT map is the target object and key is the property to add.
			if _, exists := m[key]; exists {
				// Property already exists - fail
				return jsondata.JSONValue{}, fmt.Errorf("property %q already exists", key)
			}
			newMap := make(map[string]jsondata.JSONValue, len(m)+1)
			for k, v := range m {
				newMap[k] = v
			}
			newMap[key] = v.value
			return jsondata.NewJSONValue(newMap)
		}
	}

	// Navigate deeper
	child, exists := m[key]
	if !exists {
		return jsondata.JSONValue{}, fmt.Errorf("path element %q not found", key)
	}

	newChild, err := jsondata.Accept(child, &patchMapVisitor{
		segments: remaining,
		op:       v.op,
		value:    v.value,
	})
	if err != nil {
		return jsondata.JSONValue{}, err
	}

	// Create modified copy of map
	newMap := make(map[string]jsondata.JSONValue, len(m))
	for k, v := range m {
		newMap[k] = v
	}
	newMap[key] = newChild
	return jsondata.NewJSONValue(newMap)
}

func (v *patchMapVisitor) Slice(s []jsondata.JSONValue) (jsondata.JSONValue, error) {
	if len(v.segments) == 0 {
		return jsondata.JSONValue{}, fmt.Errorf("unexpected slice at target")
	}
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into array with key %q", v.segments[0])
}

func (v *patchMapVisitor) Bool(b bool) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into bool")
}

func (v *patchMapVisitor) Float64(f float64) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into number")
}

func (v *patchMapVisitor) String(s string) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into string")
}

func (v *patchMapVisitor) Null() (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into null")
}

// applyArrayOp applies ArrayAdd or ArrayRemove to a JSON value at the given path.
func applyArrayOp(body jsondata.JSONValue, segments []string, value jsondata.JSONValue, add bool) (jsondata.JSONValue, error) {
	if len(segments) == 0 {
		// The path points directly to the root (must be an array)
		return applyArrayOpDirect(body, value, add)
	}

	// Navigate using visitor
	op := "ArrayRemove"
	if add {
		op = "ArrayAdd"
	}
	return jsondata.Accept(body, &patchMapVisitor{
		segments: segments,
		op:       op,
		value:    value,
	})
}

// applyArrayOpDirect applies ArrayAdd or ArrayRemove directly to an array value.
func applyArrayOpDirect(arr jsondata.JSONValue, value jsondata.JSONValue, add bool) (jsondata.JSONValue, error) {
	// Must be an array
	result, err := jsondata.Accept(arr, &arrayOpVisitor{value: value, add: add})
	return result, err
}

// arrayOpVisitor applies an array operation.
type arrayOpVisitor struct {
	value jsondata.JSONValue
	add   bool
}

func (v *arrayOpVisitor) Slice(s []jsondata.JSONValue) (jsondata.JSONValue, error) {
	if v.add {
		// Add if not already present
		for _, elem := range s {
			if elem.Equal(v.value) {
				// Already exists; return unchanged
				newSlice := make([]jsondata.JSONValue, len(s))
				copy(newSlice, s)
				return jsondata.NewJSONValue(newSlice)
			}
		}
		// Add to end
		newSlice := make([]jsondata.JSONValue, len(s)+1)
		copy(newSlice, s)
		newSlice[len(s)] = v.value
		return jsondata.NewJSONValue(newSlice)
	}
	// Remove if present
	newSlice := make([]jsondata.JSONValue, 0, len(s))
	for _, elem := range s {
		if !elem.Equal(v.value) {
			newSlice = append(newSlice, elem)
		}
	}
	return jsondata.NewJSONValue(newSlice)
}

func (v *arrayOpVisitor) Map(m map[string]jsondata.JSONValue) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected array, got object")
}

func (v *arrayOpVisitor) Bool(b bool) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected array, got bool")
}

func (v *arrayOpVisitor) Float64(f float64) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected array, got number")
}

func (v *arrayOpVisitor) String(s string) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected array, got string")
}

func (v *arrayOpVisitor) Null() (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected array, got null")
}

// applyObjectAdd applies an ObjectAdd operation.
func applyObjectAdd(body jsondata.JSONValue, segments []string, value jsondata.JSONValue) (jsondata.JSONValue, error) {
	if len(segments) == 0 {
		return body, fmt.Errorf("path for ObjectAdd must have at least one segment")
	}

	return jsondata.Accept(body, &patchMapVisitor{
		segments: segments,
		op:       "ObjectAdd",
		value:    value,
	})
}

// --- Initialization from token file ---

// LoadTokens parses a JSON object mapping usernames to tokens.
func LoadTokens(data []byte) (map[string]string, error) {
	var tokens map[string]string
	if err := json.Unmarshal(data, &tokens); err != nil {
		return nil, fmt.Errorf("invalid token file: %w", err)
	}
	return tokens, nil
}

// GetDocumentResponse builds the DocResponse for a document.
func GetDocumentResponse(path string, doc *Document) DocResponse {
	doc.mu.RLock()
	defer doc.mu.RUnlock()
	return DocResponse{
		Path: path,
		Doc:  doc.Body,
		Meta: doc.Meta,
	}
}

// GetCollectionForSubscription returns the collection and its documents for a subscription.
func (s *Store) GetCollectionWithDocs(dbName string, pathParts []string, start, end string) (*Collection, []DocResponse, error) {
	docs, err := s.QueryCollection(dbName, pathParts, start, end)
	if err != nil {
		return nil, nil, err
	}

	db, found := s.databases.Find(dbName)
	if !found {
		return nil, nil, fmt.Errorf("database does not exist")
	}

	var col *Collection
	if len(pathParts) == 0 {
		col = db.TopLevel
	} else {
		col, err = s.getCollection(dbName, pathParts)
		if err != nil {
			return nil, nil, err
		}
	}

	return col, docs, nil
}

