// Package auth implements authentication and authorization for OwlDB.
package auth

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"strings"
	"sync"
	"time"
)

const tokenLength = 16
const tokenExpiry = time.Hour

// TokenInfo holds information about a bearer token.
type TokenInfo struct {
	Username  string
	ExpiresAt time.Time
}

// Manager manages authentication tokens.
type Manager struct {
	mu     sync.RWMutex
	tokens map[string]*TokenInfo
}

// NewManager creates a new token manager.
func NewManager() *Manager {
	return &Manager{
		tokens: make(map[string]*TokenInfo),
	}
}

// Login creates a new token for the given username.
// Returns the new token.
func (m *Manager) Login(username string) (string, error) {
	token, err := generateToken()
	if err != nil {
		return "", fmt.Errorf("failed to generate token: %w", err)
	}

	m.mu.Lock()
	m.tokens[token] = &TokenInfo{
		Username:  username,
		ExpiresAt: time.Now().Add(tokenExpiry),
	}
	m.mu.Unlock()

	return token, nil
}

// Logout invalidates the given token.
// Returns the username if the token was valid.
func (m *Manager) Logout(token string) (string, bool) {
	m.mu.Lock()
	defer m.mu.Unlock()

	info, exists := m.tokens[token]
	if !exists {
		return "", false
	}
	if time.Now().After(info.ExpiresAt) {
		delete(m.tokens, token)
		return "", false
	}

	username := info.Username
	delete(m.tokens, token)
	return username, true
}

// Validate checks if a bearer token is valid.
// Returns the username and true if valid, or empty string and false if not.
func (m *Manager) Validate(token string) (string, bool) {
	m.mu.RLock()
	info, exists := m.tokens[token]
	m.mu.RUnlock()

	if !exists {
		return "", false
	}
	if time.Now().After(info.ExpiresAt) {
		// Token expired; remove it
		m.mu.Lock()
		delete(m.tokens, token)
		m.mu.Unlock()
		return "", false
	}
	return info.Username, true
}

// AddToken adds a pre-existing token with a long expiry (from token file).
func (m *Manager) AddToken(token, username string, expiry time.Duration) {
	m.mu.Lock()
	m.tokens[token] = &TokenInfo{
		Username:  username,
		ExpiresAt: time.Now().Add(expiry),
	}
	m.mu.Unlock()
}

// ExtractBearerToken extracts the bearer token from an Authorization header value.
// Returns the token and true if successful.
func ExtractBearerToken(authHeader string) (string, bool) {
	const prefix = "Bearer "
	if !strings.HasPrefix(authHeader, prefix) {
		return "", false
	}
	token := strings.TrimSpace(authHeader[len(prefix):])
	if token == "" {
		return "", false
	}
	return token, true
}

// generateToken generates a cryptographically random token.
func generateToken() (string, error) {
	b := make([]byte, tokenLength)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	// Use URL-safe base64 without padding
	token := base64.RawURLEncoding.EncodeToString(b)
	return token, nil
}

// Package handlers implements the HTTP request handlers for OwlDB.
package handlers

import (
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"strings"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-p1/auth"
	"github.com/RICE-COMP318-FALL24/owldb-p1/db"
	"github.com/santhosh-tekuri/jsonschema/v5"
)

// Handler holds the shared state for all HTTP handlers.
type Handler struct {
	store    *db.Store
	authMgr  *auth.Manager
	schema   *jsonschema.Schema
}

// New creates a new Handler.
func New(store *db.Store, authMgr *auth.Manager, schema *jsonschema.Schema) *Handler {
	return &Handler{
		store:   store,
		authMgr: authMgr,
		schema:  schema,
	}
}

// writeJSON writes a JSON response.
func writeJSON(w http.ResponseWriter, status int, v any) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	if err := json.NewEncoder(w).Encode(v); err != nil {
		slog.Error("Failed to write response", "error", err)
	}
}

// writeError writes a JSON error string response.
func writeError(w http.ResponseWriter, status int, msg string) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	b, _ := json.Marshal(msg)
	w.Write(b)
	w.Write([]byte("\n"))
}

// setCORSHeaders sets common CORS headers.
func setCORSHeaders(w http.ResponseWriter) {
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.Header().Set("Access-Control-Allow-Methods", "GET, PUT, POST, PATCH, DELETE, OPTIONS")
	w.Header().Set("Access-Control-Allow-Headers", "Authorization, Content-Type")
	w.Header().Set("Access-Control-Expose-Headers", "Location")
}

// validateAuth checks the Authorization header and returns the username.
// If invalid, writes a 401 response and returns "".
func (h *Handler) validateAuth(w http.ResponseWriter, r *http.Request) (string, bool) {
	authHeader := r.Header.Get("Authorization")
	token, ok := auth.ExtractBearerToken(authHeader)
	if !ok {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return "", false
	}
	username, ok := h.authMgr.Validate(token)
	if !ok {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return "", false
	}
	return username, true
}

// RegisterRoutes registers all routes on the given mux.
func (h *Handler) RegisterRoutes(mux *http.ServeMux) {
	mux.HandleFunc("/auth", h.handleAuth)
	mux.HandleFunc("/v1/", h.handleV1)
}

// handleAuth handles POST /auth (login) and DELETE /auth (logout).
func (h *Handler) handleAuth(w http.ResponseWriter, r *http.Request) {
	setCORSHeaders(w)

	if r.Method == http.MethodOptions {
		w.Header().Set("Allow", "POST, DELETE, OPTIONS")
		w.WriteHeader(http.StatusNoContent)
		return
	}

	switch r.Method {
	case http.MethodPost:
		h.handleLogin(w, r)
	case http.MethodDelete:
		h.handleLogout(w, r)
	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

// handleLogin handles POST /auth.
func (h *Handler) handleLogin(w http.ResponseWriter, r *http.Request) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}

	var req struct {
		Username string `json:"username"`
	}
	if err := json.Unmarshal(body, &req); err != nil || req.Username == "" {
		writeError(w, http.StatusBadRequest, "No username in request body")
		return
	}

	token, err := h.authMgr.Login(req.Username)
	if err != nil {
		writeError(w, http.StatusInternalServerError, "Failed to generate token")
		return
	}

	slog.Info("Login", "username", req.Username)
	writeJSON(w, http.StatusOK, map[string]string{"token": token})
}

// handleLogout handles DELETE /auth.
func (h *Handler) handleLogout(w http.ResponseWriter, r *http.Request) {
	authHeader := r.Header.Get("Authorization")
	token, ok := auth.ExtractBearerToken(authHeader)
	if !ok {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	_, ok = h.authMgr.Logout(token)
	if !ok {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	slog.Info("Logout")
	w.WriteHeader(http.StatusNoContent)
}

// handleV1 handles all /v1/... routes.
func (h *Handler) handleV1(w http.ResponseWriter, r *http.Request) {
	setCORSHeaders(w)

	if r.Method == http.MethodOptions {
		w.Header().Set("Allow", "GET, PUT, POST, PATCH, DELETE, OPTIONS")
		w.WriteHeader(http.StatusNoContent)
		return
	}

	// Parse the path: /v1/{rest}
	path := r.URL.Path
	if !strings.HasPrefix(path, "/v1/") {
		writeError(w, http.StatusNotFound, "Not found")
		return
	}

	rest := path[len("/v1/"):]
	trailingSlash := strings.HasSuffix(rest, "/")

	// Split into components
	if trailingSlash {
		rest = rest[:len(rest)-1]
	}

	parts := []string{}
	if rest != "" {
		parts = strings.Split(rest, "/")
	}

	if len(parts) == 0 {
		writeError(w, http.StatusBadRequest, "Missing database name")
		return
	}

	dbName := parts[0]
	resourceParts := parts[1:] // parts after database name

	slog.Debug("Request", "method", r.Method, "path", path, "db", dbName, "parts", resourceParts, "trailing", trailingSlash)

	// Determine resource type based on trailing slash and length
	if trailingSlash {
		if len(resourceParts) == 0 {
			// Database: /v1/{database}/
			h.handleDatabase(w, r, dbName)
		} else {
			// Collection: /v1/{database}/{collectionPath}/
			h.handleCollection(w, r, dbName, resourceParts)
		}
	} else {
		if len(resourceParts) == 0 {
			// Database without trailing slash - invalid
			writeError(w, http.StatusBadRequest, "Database path must end with /")
			return
		}
		// Document: /v1/{database}/{documentPath}
		h.handleDocument(w, r, dbName, resourceParts)
	}
}

// handleDatabase handles /v1/{database}/ routes.
func (h *Handler) handleDatabase(w http.ResponseWriter, r *http.Request, dbName string) {
	switch r.Method {
	case http.MethodPut:
		// Create database
		username, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		_ = username

		if err := h.store.CreateDatabase(dbName); err != nil {
			writeError(w, http.StatusBadRequest, err.Error())
			return
		}

		location := "/v1/" + dbName + "/"
		w.Header().Set("Location", location)
		slog.Info("Database created", "name", dbName)
		writeJSON(w, http.StatusCreated, map[string]string{"uri": location})

	case http.MethodDelete:
		// Delete database
		_, ok := h.validateAuth(w, r)
		if !ok {
			return
		}

		_, removed := h.store.DeleteDatabase(dbName)
		if !removed {
			writeError(w, http.StatusNotFound, "Database does not exist")
			return
		}

		slog.Info("Database deleted", "name", dbName)
		w.WriteHeader(http.StatusNoContent)

	case http.MethodGet:
		// Query top-level collection (database)
		_, ok := h.validateAuth(w, r)
		if !ok {
			return
		}

		start, end, err := parseInterval(r.URL.Query().Get("interval"))
		if err != nil {
			writeError(w, http.StatusBadRequest, err.Error())
			return
		}

		mode := r.URL.Query().Get("mode")
		if mode == "subscribe" {
			h.handleCollectionSubscribe(w, r, dbName, []string{}, start, end)
			return
		}

		docs, err := h.store.QueryCollection(dbName, []string{}, start, end)
		if err != nil {
			if strings.Contains(err.Error(), "does not exist") {
				writeError(w, http.StatusNotFound, err.Error())
			} else {
				writeError(w, http.StatusBadRequest, err.Error())
			}
			return
		}

		writeJSON(w, http.StatusOK, docs)

	case http.MethodPost:
		// POST to database = upload to top-level collection
		username, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		h.handlePostDocument(w, r, dbName, []string{}, username)

	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

// handleCollection handles /v1/{database}/{collectionPath}/ routes.
func (h *Handler) handleCollection(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	switch r.Method {
	case http.MethodPut:
		// Create collection
		_, ok := h.validateAuth(w, r)
		if !ok {
			return
		}

		if err := h.store.CreateCollection(dbName, pathParts); err != nil {
			if strings.Contains(err.Error(), "document does not exist") {
				writeError(w, http.StatusNotFound, "Document does not exist")
			} else if strings.Contains(err.Error(), "already exists") {
				writeError(w, http.StatusBadRequest, err.Error())
			} else {
				writeError(w, http.StatusBadRequest, err.Error())
			}
			return
		}

		location := "/v1/" + dbName + "/" + strings.Join(pathParts, "/") + "/"
		w.Header().Set("Location", location)
		slog.Info("Collection created", "path", location)
		writeJSON(w, http.StatusCreated, map[string]string{"uri": location})

	case http.MethodDelete:
		// Delete collection
		_, ok := h.validateAuth(w, r)
		if !ok {
			return
		}

		removedCol, removed := h.store.DeleteCollection(dbName, pathParts)
		if !removed {
			writeError(w, http.StatusNotFound, "Collection does not exist")
			return
		}

		// Notify collection subscribers
		if removedCol != nil {
			colPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/") + "/"
			event := db.Event{
				Type: db.EventDelete,
				Path: colPath,
			}
			removedCol.NotifySubscribers(event)
		}

		slog.Info("Collection deleted", "path", strings.Join(pathParts, "/"))
		w.WriteHeader(http.StatusNoContent)

	case http.MethodGet:
		// Query collection
		_, ok := h.validateAuth(w, r)
		if !ok {
			return
		}

		start, end, err := parseInterval(r.URL.Query().Get("interval"))
		if err != nil {
			writeError(w, http.StatusBadRequest, err.Error())
			return
		}

		mode := r.URL.Query().Get("mode")
		if mode == "subscribe" {
			h.handleCollectionSubscribe(w, r, dbName, pathParts, start, end)
			return
		}

		docs, err := h.store.QueryCollection(dbName, pathParts, start, end)
		if err != nil {
			if strings.Contains(err.Error(), "does not exist") {
				writeError(w, http.StatusNotFound, err.Error())
			} else {
				writeError(w, http.StatusBadRequest, err.Error())
			}
			return
		}

		writeJSON(w, http.StatusOK, docs)

	case http.MethodPost:
		// POST to collection = upload document
		username, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		h.handlePostDocument(w, r, dbName, pathParts, username)

	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

// handleDocument handles /v1/{database}/{documentPath} routes.
func (h *Handler) handleDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	switch r.Method {
	case http.MethodGet:
		// Get document
		_, ok := h.validateAuth(w, r)
		if !ok {
			return
		}

		mode := r.URL.Query().Get("mode")
		if mode == "subscribe" {
			h.handleDocumentSubscribe(w, r, dbName, pathParts)
			return
		}

		doc, err := h.store.GetDocument(dbName, pathParts)
		if err != nil {
			if strings.Contains(err.Error(), "does not exist") {
				writeError(w, http.StatusNotFound, err.Error())
			} else {
				writeError(w, http.StatusBadRequest, err.Error())
			}
			return
		}

		fullPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
		resp := db.GetDocumentResponse(fullPath, doc)
		writeJSON(w, http.StatusOK, resp)

	case http.MethodPut:
		// Create or replace document
		username, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		h.handlePutDocument(w, r, dbName, pathParts, username)

	case http.MethodPost:
		// POST to a document path is not valid (should have trailing slash)
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")

	case http.MethodPatch:
		// Patch document
		username, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		h.handlePatchDocument(w, r, dbName, pathParts, username)

	case http.MethodDelete:
		// Delete document
		_, ok := h.validateAuth(w, r)
		if !ok {
			return
		}
		h.handleDeleteDocument(w, r, dbName, pathParts)

	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

// handlePutDocument handles PUT /v1/{database}/{documentPath}.
func (h *Handler) handlePutDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}

	// Parse and validate document
	docVal, err := parseAndValidateDocument(body, h.schema)
	if err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	mode := r.URL.Query().Get("mode")
	if mode == "" {
		mode = "overwrite"
	}

	wasUpdated, err := h.store.PutDocument(dbName, pathParts, docVal, username, mode)
	if err != nil {
		if conflictErr, ok := err.(*db.ConflictError); ok {
			writeError(w, http.StatusPreconditionFailed, conflictErr.Message)
			return
		}
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, err.Error())
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	fullPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	w.Header().Set("Location", fullPath)

	if wasUpdated {
		slog.Info("Document updated", "path", fullPath)
		writeJSON(w, http.StatusOK, map[string]string{"uri": fullPath})
	} else {
		slog.Info("Document created", "path", fullPath)
		writeJSON(w, http.StatusCreated, map[string]string{"uri": fullPath})
	}
}

// handlePostDocument handles POST to a collection.
func (h *Handler) handlePostDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}

	docVal, err := parseAndValidateDocument(body, h.schema)
	if err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	docName, err := h.store.PostDocument(dbName, pathParts, docVal, username)
	if err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, err.Error())
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	var fullPath string
	if len(pathParts) == 0 {
		fullPath = "/v1/" + dbName + "/" + docName
	} else {
		fullPath = "/v1/" + dbName + "/" + strings.Join(pathParts, "/") + "/" + docName
	}

	w.Header().Set("Location", fullPath)
	slog.Info("Document posted", "path", fullPath)
	writeJSON(w, http.StatusCreated, map[string]string{"uri": fullPath})
}

// handleDeleteDocument handles DELETE /v1/{database}/{documentPath}.
func (h *Handler) handleDeleteDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	_, err := h.store.DeleteDocument(dbName, pathParts)
	if err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, err.Error())
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	fullPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	slog.Info("Document deleted", "path", fullPath)
	w.WriteHeader(http.StatusNoContent)
}

// handlePatchDocument handles PATCH /v1/{database}/{documentPath}.
func (h *Handler) handlePatchDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}

	var patches []db.PatchOperation
	if err := json.Unmarshal(body, &patches); err != nil {
		writeError(w, http.StatusBadRequest, fmt.Sprintf("Invalid patch body: %s", err.Error()))
		return
	}

	result, err := h.store.PatchDocument(dbName, pathParts, patches, username)
	if err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, err.Error())
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	fullPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	w.Header().Set("Location", fullPath)
	writeJSON(w, http.StatusOK, result)
}

// handleDocumentSubscribe handles SSE subscription to a document.
func (h *Handler) handleDocumentSubscribe(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	// Set SSE headers
	flusher, ok := w.(http.Flusher)
	if !ok {
		writeError(w, http.StatusInternalServerError, "Streaming not supported")
		return
	}

	// Get current document state first
	doc, err := h.store.GetDocument(dbName, pathParts)
	if err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, err.Error())
		} else {
			writeError(w, http.StatusBadRequest, err.Error())
		}
		return
	}

	ch, unsubscribe, err := h.store.SubscribeDocument(dbName, pathParts)
	if err != nil {
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}
	defer unsubscribe()

	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.WriteHeader(http.StatusOK)

	// Send current document state as initial update event
	fullPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	doc.RLock()
	body := doc.Body
	meta := doc.Meta
	doc.RUnlock()
	sendUpdateEvent(w, fullPath, &body, &meta)
	flusher.Flush()

	// Heartbeat ticker
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case event, ok := <-ch:
			if !ok {
				return
			}
			if event.Type == db.EventUpdate {
				sendUpdateEvent(w, event.Path, event.Doc, event.Meta)
			} else {
				sendDeleteEvent(w, event.Path)
			}
			flusher.Flush()

		case <-ticker.C:
			// Send heartbeat comment
			fmt.Fprintf(w, ": heartbeat\n\n")
			flusher.Flush()

		case <-r.Context().Done():
			return
		}
	}
}

// handleCollectionSubscribe handles SSE subscription to a collection.
func (h *Handler) handleCollectionSubscribe(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, start, end string) {
	flusher, ok := w.(http.Flusher)
	if !ok {
		writeError(w, http.StatusInternalServerError, "Streaming not supported")
		return
	}

	// Get the collection for subscription
	col, initialDocs, err := h.store.GetCollectionWithDocs(dbName, pathParts, start, end)
	if err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, err.Error())
		} else {
			writeError(w, http.StatusBadRequest, err.Error())
		}
		return
	}

	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.WriteHeader(http.StatusOK)

	// Subscribe before sending initial docs to avoid missing events
	ch := make(chan db.Event, 100)
	col.AddSubscriber(ch)
	defer col.RemoveSubscriber(ch)

	// Send initial documents
	for _, doc := range initialDocs {
		sendUpdateEvent(w, doc.Path, &doc.Doc, &doc.Meta)
	}
	flusher.Flush()

	// Heartbeat ticker
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case event, ok := <-ch:
			if !ok {
				return
			}
			// Filter by interval if specified
			if start != "" || end != "" {
				// Extract document name from path
				docName := extractDocName(event.Path)
				if start != "" && docName < start {
					continue
				}
				if end != "" && docName > end {
					continue
				}
			}
			if event.Type == db.EventUpdate {
				sendUpdateEvent(w, event.Path, event.Doc, event.Meta)
			} else {
				sendDeleteEvent(w, event.Path)
			}
			flusher.Flush()

		case <-ticker.C:
			fmt.Fprintf(w, ": heartbeat\n\n")
			flusher.Flush()

		case <-r.Context().Done():
			return
		}
	}
}

// sendUpdateEvent sends an SSE update event.
func sendUpdateEvent(w http.ResponseWriter, path string, docBody *db.JSONValue, meta *db.Metadata) {
	type updateData struct {
		Path string          `json:"path"`
		Doc  db.JSONValue    `json:"doc"`
		Meta db.Metadata     `json:"meta"`
	}

	data := updateData{
		Path: path,
		Doc:  *docBody,
		Meta: *meta,
	}

	dataBytes, err := json.Marshal(data)
	if err != nil {
		return
	}

	id := time.Now().UnixMilli()
	fmt.Fprintf(w, "event: update\ndata: %s\nid: %d\n\n", string(dataBytes), id)
}

// sendDeleteEvent sends an SSE delete event.
func sendDeleteEvent(w http.ResponseWriter, path string) {
	pathBytes, err := json.Marshal(path)
	if err != nil {
		return
	}
	id := time.Now().UnixMilli()
	fmt.Fprintf(w, "event: delete\ndata: %s\nid: %d\n\n", string(pathBytes), id)
}

// parseAndValidateDocument parses and validates a JSON document body.
func parseAndValidateDocument(body []byte, schema *jsonschema.Schema) (db.JSONValue, error) {
	var docVal db.JSONValue
	if err := json.Unmarshal(body, &docVal); err != nil {
		return db.JSONValue{}, fmt.Errorf("invalid JSON: %s", err.Error())
	}

	if schema != nil {
		if err := docVal.Validate(schema); err != nil {
			return db.JSONValue{}, fmt.Errorf("document does not conform to schema: %s", err.Error())
		}
	}

	return docVal, nil
}

// parseInterval parses an interval query parameter like "[low,high]".
func parseInterval(interval string) (start, end string, err error) {
	if interval == "" {
		return "", "", nil
	}

	if !strings.HasPrefix(interval, "[") || !strings.HasSuffix(interval, "]") {
		return "", "", fmt.Errorf("invalid interval format: must be [low,high]")
	}

	inner := interval[1 : len(interval)-1]
	idx := strings.Index(inner, ",")
	if idx == -1 {
		return "", "", fmt.Errorf("invalid interval format: missing comma")
	}

	start = strings.TrimSpace(inner[:idx])
	end = strings.TrimSpace(inner[idx+1:])
	return start, end, nil
}

// extractDocName extracts the last component of a path.
func extractDocName(path string) string {
	path = strings.TrimSuffix(path, "/")
	idx := strings.LastIndex(path, "/")
	if idx == -1 {
		return path
	}
	return path[idx+1:]
}

