// Document represents a single document stored in the database.
type Document struct {
	Body        jsondata.JSONValue
	Meta        Metadata
	Collections *skiplist.SkipList[string, *Collection]
	mu          sync.RWMutex
	// docSubscribers are channels that should be notified when this doc changes
	docSubscribers []chan Event
	dsMu           sync.Mutex
}

// RLock locks the document for reading.
func (d *Document) RLock() { d.mu.RLock() }

// RUnlock unlocks the document read lock.
func (d *Document) RUnlock() { d.mu.RUnlock() }

// Collection represents a collection of documents stored in a skip list.
type Collection struct {
	Index *skiplist.SkipList[string, *Document]
	// colSubscribers are channels notified when any doc in this collection changes
	colSubscribers []chan Event
	csMu           sync.Mutex
}

// AddSubscriber adds a subscriber channel to the collection.
func (c *Collection) AddSubscriber(ch chan Event) {
	c.csMu.Lock()
	c.colSubscribers = append(c.colSubscribers, ch)
	c.csMu.Unlock()
}

// RemoveSubscriber removes a subscriber channel from the collection.
func (c *Collection) RemoveSubscriber(ch chan Event) {
	c.csMu.Lock()
	for i, sub := range c.colSubscribers {
		if sub == ch {
			c.colSubscribers = append(c.colSubscribers[:i], c.colSubscribers[i+1:]...)
			break
		}
	}
	c.csMu.Unlock()
	close(ch)
}

// NotifySubscribers notifies all collection subscribers.
func (c *Collection) NotifySubscribers(event Event) {
	notifyColSubscribers(c, event)
}

