// lockPredsForRemove locks preds ensuring each points to nodeToDelete.
func (sl *SkipList[K, V]) lockPredsForRemove(r findResult[K, V], topLevel int, nodeToDelete *node[K, V]) (lockedPreds [maxLevel]*node[K, V], highestLocked int, valid bool) {
