		}
		if !curr.marked.Load() && curr.fullyLinked.Load() {
			if hasStart && cmp.Compare(curr.key, start) < 0 {
				curr = curr.next[0].Load()
				continue
			}
			if hasEnd && cmp.Compare(curr.key, end) > 0 {
