			highestLocked = level
			prevPred = pred
		}
		lockedPreds[level] = pred

		if pred.marked.Load() || pred.next[level].Load() != nodeToDelete {
			valid = false
		}
	}
	return lockedPreds, highestLocked, valid
}

// unlockPreds releases unique predecessor locks.
func unlockPreds[K cmp.Ordered, V any](lockedPreds [maxLevel]*node[K, V], highestLocked int) {
	var prevPred *node[K, V]
	for level := 0; level <= highestLocked; level++ {
		if lockedPreds[level] != prevPred {
			lockedPreds[level].mu.Unlock()
			prevPred = lockedPreds[level]
		}
	}
}

// Upsert inserts or updates key in the skip list.
